import { createContext, useContext, useState, useEffect, ReactNode } from "react";
import type { WikiArticle } from "../components/WikiCard";
import { Heart } from "lucide-react";
import '../assets/heartAnimation.css';

interface LikedArticlesContextType {
    likedArticles: WikiArticle[];
    toggleLike: (article: WikiArticle) => void;
    isLiked: (pageid: number) => boolean;
}

const LikedArticlesContext = createContext<LikedArticlesContextType | undefined>(undefined);

export function LikedArticlesProvider({ children }: { children: ReactNode }) {
    const [likedArticles, setLikedArticles] = useState<WikiArticle[]>(() => {
        const saved = localStorage.getItem("likedArticles");
        return saved ? JSON.parse(saved) : [];
    });

    const [showHeart, setShowHeart] = useState(false);

    useEffect(() => {
        localStorage.setItem("likedArticles", JSON.stringify(likedArticles));
    }, [likedArticles]);

    const toggleLike = (article: WikiArticle) => {
        setLikedArticles((prev) => {
            const alreadyLiked = prev.some((a) => a.pageid === article.pageid);
            if (alreadyLiked) {
                return prev.filter((a) => a.pageid !== article.pageid);
            } else {
                setShowHeart(true);
                setTimeout(() => setShowHeart(false), 800);
                return [...prev, article];
            }
        });
    };

    const isLiked = (pageid: number) => {
        return likedArticles.some((article) => article.pageid === pageid);
    };

    return (
        <LikedArticlesContext.Provider value={{ likedArticles, toggleLike, isLiked }}>
            {children}
            {showHeart && (
                <div className="heart-animation">
                    <Heart size={200} strokeWidth={0} className="fill-white"/>
                </div>
            )}
        </LikedArticlesContext.Provider>
    );
}

export function useLikedArticles() {
    const context = useContext(LikedArticlesContext);
    if (!context) {
        throw new Error("useLikedArticles must be used within a LikedArticlesProvider");
    }
    return context;
}

import { useState, useEffect, useCallback } from "react";
import { LANGUAGES } from "../languages";

export function useLocalization() {
  const getInitialLanguage = useCallback(() => {
    const savedLanguageId = localStorage.getItem("lang");
    return (
      LANGUAGES.find((lang) => lang.id === savedLanguageId) || LANGUAGES[0]
    );
  }, []);

  const [currentLanguage, setCurrentLanguage] = useState(getInitialLanguage);

  useEffect(() => {
    localStorage.setItem("lang", currentLanguage.id);
  }, [currentLanguage]);

  const setLanguage = (languageId: string) => {
    const newLanguage = LANGUAGES.find((lang) => lang.id === languageId);
    if (newLanguage) {
      setCurrentLanguage(newLanguage);
      window.location.reload();
    } else {
      console.warn(`Language not found: ${languageId}`);
    }
  };

  return {
    currentLanguage,
    setLanguage,
  };
}

import { useState, useCallback } from "react";
import { useLocalization } from "./useLocalization";
import type { WikiArticle } from "../components/WikiCard";

const preloadImage = (src: string): Promise<void> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.src = src;
    img.onload = () => resolve();
    img.onerror = reject;
  });
};

export function useWikiArticles() {
  const [articles, setArticles] = useState<WikiArticle[]>([]);
  const [loading, setLoading] = useState(false);
  const [buffer, setBuffer] = useState<WikiArticle[]>([]);
  const { currentLanguage } = useLocalization();

  const fetchArticles = async (forBuffer = false) => {
    if (loading) return;
    setLoading(true);
    try {
      const response = await fetch(
        currentLanguage.api +
          new URLSearchParams({
            action: "query",
            format: "json",
            generator: "random",
            grnnamespace: "0",
            prop: "extracts|info|pageimages",
            inprop: "url|varianttitles",
            grnlimit: "20",
            exintro: "1",
            exlimit: "max",
            exsentences: "5",
            explaintext: "1",
            piprop: "thumbnail",
            pithumbsize: "800",
            origin: "*",
            variant: currentLanguage.id,
          })
      );

      const data = await response.json();
      const newArticles = Object.values(data.query.pages)
        .map(
          (page: any): WikiArticle => ({
            title: page.title,
            displaytitle: page.varianttitles[currentLanguage.id],
            extract: page.extract,
            pageid: page.pageid,
            thumbnail: page.thumbnail,
            url: page.canonicalurl,
          })
        )
        .filter(
          (article) =>
            article.thumbnail &&
            article.thumbnail.source &&
            article.url &&
            article.extract
        );

      await Promise.allSettled(
        newArticles
          .filter((article) => article.thumbnail)
          .map((article) => preloadImage(article.thumbnail!.source))
      );

      if (forBuffer) {
        setBuffer(newArticles);
      } else {
        setArticles((prev) => [...prev, ...newArticles]);
        fetchArticles(true);
      }
    } catch (error) {
      console.error("Error fetching articles:", error);
    }
    setLoading(false);
  };

  const getMoreArticles = useCallback(() => {
    if (buffer.length > 0) {
      setArticles((prev) => [...prev, ...buffer]);
      setBuffer([]);
      fetchArticles(true);
    } else {
      fetchArticles(false);
    }
  }, [buffer]);

  return { articles, loading, fetchArticles: getMoreArticles };
}

import { FC } from 'react';

interface ArticleProps {
  title: string;
  content: string;
  image?: string;
}

const Article: FC<ArticleProps> = ({ title, content, image }) => {
  return (
    <article 
      className="article-container"
      role="article"
      aria-labelledby="article-title"
    >
      <h2 id="article-title" className="article-title">
        {title}
      </h2>

      {image && (
        <img 
          src={image} 
          alt={`Illustration for article: ${title}`}
          className="article-image"
        />
      )}

      <div 
        className="article-content"
        role="contentinfo"
        aria-label="Article content"
      >
        {content}
      </div>
    </article>
  );
};

export default Article;

import { useState, useEffect, useRef } from "react";
import { LANGUAGES } from "../languages";
import { useLocalization } from "../hooks/useLocalization";

export function LanguageSelector() {
  const [showDropdown, setShowDropdown] = useState(false);
  const { setLanguage } = useLocalization();
  const dropdownRef = useRef<HTMLDivElement>(null);

  const handleClickOutside = (event: MouseEvent) => {
    if (
      dropdownRef.current &&
      !dropdownRef.current.contains(event.target as Node)
    ) {
      setShowDropdown(false);
    }
  };

  useEffect(() => {
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  return (
    <div
      className="relative inline-flex items-center"
      onClick={() => setShowDropdown(!showDropdown)}
      ref={dropdownRef}
    >
      <button className="text-sm text-white/70 hover:text-white transition-colors">
        Language
      </button>

      {showDropdown && (
        <div className="absolute overflow-y-auto max-h-[205px] py-2 w-40 right-0 top-full mt-1 bg-gray-900 rounded-md shadow-lg">
          {LANGUAGES.sort((a,b) => a.id.localeCompare(b.id)).map((language) => (
            <button
              key={language.id}
              onClick={() => setLanguage(language.id)}
              className="w-full items-center flex gap-3 px-3 py-1 hover:bg-gray-800"
            >
              <img className="w-5" src={language.flag} alt={language.name} />
              <span className="text-xs">{language.name}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

import { FC, KeyboardEvent } from 'react';
import Article from './Article';
import { ArticleProps } from '../types/ArticleProps';
interface ArticleListProps {
  articles: ArticleProps[];
  onArticleSelect?: (article: ArticleProps) => void;
}

const ArticleList: FC<ArticleListProps> = ({ articles, onArticleSelect }) => {
  const handleKeyPress = (e: KeyboardEvent<HTMLLIElement>, article: ArticleProps) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onArticleSelect?.(article);
    }
  };

  const handleClick = (article: ArticleProps) => {
    onArticleSelect?.(article);
  };

  return (
    <nav aria-label="Articles navigation">
      <ul 
        role="list"
        className="articles-list"
      >
        {articles.map((article, index) => (
          <li 
            key={index}
            role="listitem"
            tabIndex={0}
            onClick={() => handleClick(article)}
            onKeyPress={(e) => handleKeyPress(e, article)}
            aria-label={`Article: ${article.title}`}
          >
            <Article {...article} />
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default ArticleList;

import { Share2, Heart } from 'lucide-react';
import { useState } from 'react';
import { useLikedArticles } from '../contexts/LikedArticlesContext';

export interface WikiArticle {
    title: string;
    displaytitle: string;
    extract: string;
    pageid: number;
    url: string;
    thumbnail: {
        source: string;
        width: number;
        height: number;
    };
}

interface WikiCardProps {
    article: WikiArticle;
}

export function WikiCard({ article }: WikiCardProps) {
    const [imageLoaded, setImageLoaded] = useState(false);
    const { toggleLike, isLiked } = useLikedArticles();

    // Add debugging log
    console.log('Article data:', {
        title: article.title,
        displaytitle: article.displaytitle,
        pageid: article.pageid
    });

    const handleShare = async () => {
        if (navigator.share) {
            try {
                await navigator.share({
                    title: article.displaytitle,
                    text: article.extract || '',
                    url: article.url
                });
            } catch (error) {
                console.error('Error sharing:', error);
            }
        } else {
            // Fallback: Copy to clipboard
            await navigator.clipboard.writeText(article.url);
            alert('Link copied to clipboard!');
        }
    };

    return (
        <div className="h-screen w-full flex items-center justify-center snap-start relative" onDoubleClick={() => toggleLike(article)}>
            <div className="h-full w-full relative">
                {article.thumbnail ? (
                    <div className="absolute inset-0">
                        <img
                            loading="lazy"
                            src={article.thumbnail.source}
                            alt={article.displaytitle}
                            className={`w-full h-full object-cover transition-opacity duration-300 bg-white ${imageLoaded ? 'opacity-100' : 'opacity-0'
                                }`}
                            onLoad={() => setImageLoaded(true)}
                            onError={(e) => {
                                console.error('Image failed to load:', e);
                                setImageLoaded(true); // Show content even if image fails
                            }}
                        />
                        {!imageLoaded && (
                            <div className="absolute inset-0 bg-gray-900 animate-pulse" />
                        )}
                        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black/60" />
                    </div>
                ) : (
                    <div className="absolute inset-0 bg-gray-900" />
                )}
                {/* Content container with z-index to ensure it's above the image */}
                <div className="absolute backdrop-blur-xs bg-black/30 bottom-[10vh] left-0 right-0 p-6 text-white z-10">
                    <div className="flex justify-between items-start mb-3">
                        <a
                            href={article.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="hover:text-gray-200 transition-colors"
                        >
                            <h2 className="text-2xl font-bold drop-shadow-lg">{article.displaytitle}</h2>
                        </a>
                        <div className="flex gap-2">
                            <button
                                onClick={() => toggleLike(article)}
                                className={`p-2 rounded-full backdrop-blur-sm transition-colors ${isLiked(article.pageid)
                                    ? 'bg-red-500 hover:bg-red-600'
                                    : 'bg-white/10 hover:bg-white/20'
                                    }`}
                                aria-label="Like article"
                            >
                                <Heart
                                    className={`w-5 h-5 ${isLiked(article.pageid) ? 'fill-white' : ''}`}
                                />
                            </button>
                            <button
                                onClick={handleShare}
                                className="p-2 rounded-full bg-white/10 backdrop-blur-sm hover:bg-white/20 transition-colors"
                                aria-label="Share article"
                            >
                                <Share2 className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                    <p className="text-gray-100 mb-4 drop-shadow-lg line-clamp-6">{article.extract}</p>
                    <a
                        href={article.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="inline-block text-white hover:text-gray-200 drop-shadow-lg"
                    >
                        Read more →
                    </a>
                </div>
            </div>
        </div>
    );
}

