    61	function installFetchMock(articles: WikiArticle[]) {
    62	  const originalFetch = globalThis.fetch;
    63	  const body = JSON.stringify(createFetchResponse(articles));
    64	
    65	  const mockFetch: typeof fetch = async () =>
    66	    new Response(body, {
    67	      headers: {
    68	        'Content-Type': 'application/json',
    69	      },
    70	    });
    71	
    72	  globalThis.fetch = mockFetch;
    73	
    74	  return () => {
